        "id":  "C034-alternance-gauche-droite-et-attention",
        "number":  34,
        "familyId":  "rythmes",
        "familyTitle":  "Rythmes, nombre d'or & fractales",
        "symbol":  "φ",
        "title":  "Alternance gauche-droite et attention",
