        "id":  "C041-ce-qui-est-en-haut-comme-ce-qui-est-en-bas",
        "number":  41,
        "familyId":  "inversion",
        "familyTitle":  "Inversion & incarnation",
        "symbol":  "↧",
        "title":  "Ce qui est en haut comme ce qui est en bas",
