(function () {
  if (Array.isArray(window.AXIS_ONE_HOUR_COURSES)) {
    window.AXIS_ONE_HOUR_COURSES = window.AXIS_ONE_HOUR_COURSES
      .filter(Boolean)
      .sort((a, b) => Number(a.number || 0) - Number(b.number || 0));

    const seen = new Set();
    window.AXIS_ONE_HOUR_COURSES = window.AXIS_ONE_HOUR_COURSES.filter((course) => {
      const key = Number(course.number || 0);
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  }
})();
